import{_ as r,c as s,o as d,a7 as e,j as t,a}from"./chunks/framework.BQb8NfN9.js";const b=JSON.parse('{"title":"循环神经网络（RNN）","description":"","frontmatter":{},"headers":[],"relativePath":"ai/深度学习/循环神经网络.md","filePath":"ai/深度学习/循环神经网络.md","lastUpdated":1773670517000}'),o={name:"ai/深度学习/循环神经网络.md"};function l(h,n,p,i,c,_){return d(),s("div",null,n[0]||(n[0]=[e(`<h1 id="循环神经网络-rnn" tabindex="-1">循环神经网络（RNN） <a class="header-anchor" href="#循环神经网络-rnn" aria-label="Permalink to &quot;循环神经网络（RNN）&quot;">​</a></h1><p>循环神经网络（Recurrent Neural Network，RNN）是专门处理<strong>序列数据</strong>（文本、语音、时序信号）的神经网络。与全连接网络不同，RNN 通过<strong>隐藏状态</strong>在时间步之间传递信息，从而捕捉序列中的时间依赖关系。</p><p><strong>文档结构：</strong> RNN 结构与计算 → 时序反向传播（BPTT）→ 梯度消失问题 → LSTM → GRU → Seq2Seq → 知识小结。</p><hr><h2 id="一、rnn-结构与计算" tabindex="-1">一、RNN 结构与计算 <a class="header-anchor" href="#一、rnn-结构与计算" aria-label="Permalink to &quot;一、RNN 结构与计算&quot;">​</a></h2><h3 id="网络结构" tabindex="-1">网络结构 <a class="header-anchor" href="#网络结构" aria-label="Permalink to &quot;网络结构&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>     h_{t-1}</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>x_t → [RNN Cell] → h_t → y_t</span></span>
<span class="line"><span>        ↑</span></span>
<span class="line"><span>     同一组权重 W（参数共享）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>与普通全连接网络的关键区别：<strong>当前时刻的隐藏状态 $h_t$ 不仅取决于当前输入 $x_t$，还取决于上一时刻的隐藏状态 $h_{t-1}$。</strong></p><h3 id="数学公式" tabindex="-1">数学公式 <a class="header-anchor" href="#数学公式" aria-label="Permalink to &quot;数学公式&quot;">​</a></h3><p><strong>隐藏状态更新：</strong></p><p>$$h_t = f(W_h h_{t-1} + W_x x_t + b_h)$$</p><p><strong>输出：</strong></p><p>$$y_t = g(W_y h_t + b_y)$$</p><p>其中：</p><table tabindex="0"><thead><tr><th>符号</th><th>含义</th></tr></thead><tbody><tr><td>$x_t$</td><td>$t$ 时刻的输入（如一个词的词向量）</td></tr><tr><td>$h_t$</td><td>$t$ 时刻的隐藏状态（记忆）</td></tr><tr><td>$y_t$</td><td>$t$ 时刻的输出</td></tr><tr><td>$W_h, W_x, W_y$</td><td>可学习权重（所有时间步共享）</td></tr><tr><td>$f$</td><td>隐藏层激活函数（常用 tanh 或 ReLU）</td></tr><tr><td>$g$</td><td>输出层激活函数（Softmax 等）</td></tr></tbody></table><p><strong>参数共享：</strong> 所有时间步使用同一组 $W_h, W_x$，使 RNN 可以处理任意长度的序列。</p><h3 id="rnn-按展开方式分类" tabindex="-1">RNN 按展开方式分类 <a class="header-anchor" href="#rnn-按展开方式分类" aria-label="Permalink to &quot;RNN 按展开方式分类&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>结构</th><th>典型应用</th></tr></thead><tbody><tr><td>一对多（one-to-many）</td><td>单输入 → 序列输出</td><td>图像描述生成</td></tr><tr><td>多对一（many-to-one）</td><td>序列输入 → 单输出</td><td>情感分类</td></tr><tr><td>多对多（many-to-many）</td><td>序列输入 → 序列输出</td><td>机器翻译（Seq2Seq）</td></tr></tbody></table><hr><h2 id="二、时序反向传播-bptt" tabindex="-1">二、时序反向传播（BPTT） <a class="header-anchor" href="#二、时序反向传播-bptt" aria-label="Permalink to &quot;二、时序反向传播（BPTT）&quot;">​</a></h2><p>BPTT（Backpropagation Through Time）是标准反向传播在<strong>时间轴上的展开版本</strong>。</p><h3 id="三个步骤" tabindex="-1">三个步骤 <a class="header-anchor" href="#三个步骤" aria-label="Permalink to &quot;三个步骤&quot;">​</a></h3><ol><li><strong>前向计算</strong>：按时间顺序 $t=1,2,\\ldots,T$ 计算每个时刻的 $h_t$ 和 $y_t$，并计算损失 $\\mathcal{L} = \\sum_t \\mathcal{L}_t$。</li><li><strong>反向计算误差</strong>：从 $t=T$ 向 $t=1$ 方向，用链式法则计算每个时刻对损失的梯度 $\\partial \\mathcal{L}/\\partial h_t$。</li><li><strong>计算权重梯度</strong>：累加所有时间步对同一权重的梯度（因为参数共享），再用 SGD/Adam 更新。</li></ol><p><strong>梯度沿时间链式传播：</strong></p><p>$$\\frac{\\partial \\mathcal{L}}{\\partial h_t} = \\frac{\\partial \\mathcal{L}}{\\partial h_T} \\cdot \\prod_{k=t}^{T-1} \\frac{\\partial h_{k+1}}{\\partial h_k} = \\frac{\\partial \\mathcal{L}}{\\partial h_T} \\cdot \\prod_{k=t}^{T-1} W_h \\cdot \\text{diag}(f&#39;(h_k))$$</p><hr><h2 id="三、rnn-的问题-长程依赖" tabindex="-1">三、RNN 的问题：长程依赖 <a class="header-anchor" href="#三、rnn-的问题-长程依赖" aria-label="Permalink to &quot;三、RNN 的问题：长程依赖&quot;">​</a></h2><h3 id="梯度消失" tabindex="-1">梯度消失 <a class="header-anchor" href="#梯度消失" aria-label="Permalink to &quot;梯度消失&quot;">​</a></h3><p>当序列很长（如 $T=100$）时，反向传播需要乘以 $T$ 个 $W_h$ 矩阵。若 $\\lvert W_h\\rvert &lt; 1$，乘积指数衰减 → <strong>前几个时间步的梯度趋近于 0，远处信息被遗忘</strong>。</p><h3 id="梯度爆炸" tabindex="-1">梯度爆炸 <a class="header-anchor" href="#梯度爆炸" aria-label="Permalink to &quot;梯度爆炸&quot;">​</a></h3><p>若 $\\lvert W_h\\rvert &gt; 1$，乘积指数增大 → 参数更新不稳定（可用梯度裁剪解决）。</p><p><strong>根本原因</strong>：RNN 的隐藏状态是<strong>覆盖式更新</strong>——$h_t$ 直接被新内容覆盖，无法长期保留重要信息。LSTM 通过&quot;门控&quot;机制解决这一问题。</p><hr><h2 id="四、长短期记忆网络-lstm" tabindex="-1">四、长短期记忆网络 LSTM <a class="header-anchor" href="#四、长短期记忆网络-lstm" aria-label="Permalink to &quot;四、长短期记忆网络 LSTM&quot;">​</a></h2><p>LSTM（Long Short-Term Memory）由 Hochreiter &amp; Schmidhuber 于 1997 年提出，通过引入<strong>细胞状态（Cell State）$c_t$</strong> 和三个门控机制，解决长程依赖问题。</p><h3 id="核心思想" tabindex="-1">核心思想 <a class="header-anchor" href="#核心思想" aria-label="Permalink to &quot;核心思想&quot;">​</a></h3><p>$c_t$ 是贯穿时间步的&quot;高速公路&quot;，门控单元精确控制哪些信息被保留、被遗忘、被输出。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>c_{t-1} ──────────────────────────────→ c_t（细胞状态，长期记忆）</span></span>
<span class="line"><span>              ↑ forget  ↑ input           ↓ output</span></span>
<span class="line"><span>h_{t-1} → [遗忘门] [输入门] [输出门] → h_t（隐藏状态，短期记忆）</span></span>
<span class="line"><span>x_t ──────────────────────────────────↗</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="三个门-一个候选状态" tabindex="-1">三个门 + 一个候选状态 <a class="header-anchor" href="#三个门-一个候选状态" aria-label="Permalink to &quot;三个门 + 一个候选状态&quot;">​</a></h3><p><strong>1. 遗忘门（Forget Gate）</strong>：决定从细胞状态中丢弃多少旧信息（输出 0=完全遗忘，1=完全保留）。</p><p>$$f_t = \\sigma(W_f [h_{t-1}, x_t] + b_f)$$</p><p><strong>2. 输入门（Input Gate）</strong>：决定将多少新信息写入细胞状态。</p><p>$$i_t = \\sigma(W_i [h_{t-1}, x_t] + b_i)$$</p><p><strong>候选细胞状态</strong>（新信息内容）：</p>`,44),t("p",null,[a("$$\\tilde{c}"),t("em",{"t-1":""},"t = \\tanh(W_c [h"),a(", x_t] + b_c)$$")],-1),e('<p><strong>3. 细胞状态更新</strong>：遗忘一部分旧信息 + 写入一部分新信息。</p><p>$$c_t = f_t \\odot c_{t-1} + i_t \\odot \\tilde{c}_t$$</p><p><strong>4. 输出门（Output Gate）</strong>：决定输出多少细胞状态作为隐藏状态。</p><p>$$o_t = \\sigma(W_o [h_{t-1}, x_t] + b_o)$$</p><p>$$h_t = o_t \\odot \\tanh(c_t)$$</p><p>其中 $\\odot$ 表示逐元素乘法（Hadamard 积），$\\sigma$ 为 Sigmoid 函数。</p><h3 id="lstm-为什么解决梯度消失" tabindex="-1">LSTM 为什么解决梯度消失 <a class="header-anchor" href="#lstm-为什么解决梯度消失" aria-label="Permalink to &quot;LSTM 为什么解决梯度消失&quot;">​</a></h3><p>细胞状态 $c_t$ 的更新中包含<strong>加法项</strong> $f_t \\odot c_{t-1}$（而非乘法覆盖），梯度可直接沿 $c_t$ 链回传，不会被指数衰减。这类似于 ResNet 的残差连接。</p><hr><h2 id="五、门控循环单元-gru" tabindex="-1">五、门控循环单元 GRU <a class="header-anchor" href="#五、门控循环单元-gru" aria-label="Permalink to &quot;五、门控循环单元 GRU&quot;">​</a></h2><p>GRU（Gated Recurrent Unit，2014 年）是 LSTM 的简化版，将遗忘门和输入门合并为<strong>更新门</strong>，去掉独立的细胞状态，参数更少，训练更快。</p><h3 id="计算公式" tabindex="-1">计算公式 <a class="header-anchor" href="#计算公式" aria-label="Permalink to &quot;计算公式&quot;">​</a></h3><p><strong>重置门</strong>（控制上一隐藏状态的使用比例）：</p><p>$$r_t = \\sigma(W_r [h_{t-1}, x_t] + b_r)$$</p><p><strong>更新门</strong>（控制新旧状态的融合比例）：</p><p>$$z_t = \\sigma(W_z [h_{t-1}, x_t] + b_z)$$</p><p><strong>候选隐藏状态：</strong></p>',17),t("p",null,[a("$$\\tilde{h}"),t("em",{"t-1":""},"t = \\tanh(W_h [r_t \\odot h"),a(", x_t] + b_h)$$")],-1),e(`<p><strong>最终隐藏状态：</strong></p><p>$$h_t = (1 - z_t) \\odot h_{t-1} + z_t \\odot \\tilde{h}_t$$</p><h3 id="lstm-vs-gru" tabindex="-1">LSTM vs GRU <a class="header-anchor" href="#lstm-vs-gru" aria-label="Permalink to &quot;LSTM vs GRU&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>LSTM</th><th>GRU</th></tr></thead><tbody><tr><td>门数量</td><td>3 个（遗忘、输入、输出）</td><td>2 个（重置、更新）</td></tr><tr><td>状态</td><td>$c_t$（细胞状态）+ $h_t$</td><td>仅 $h_t$</td></tr><tr><td>参数量</td><td>较多</td><td>较少（约 LSTM 的 75%）</td></tr><tr><td>训练速度</td><td>较慢</td><td>较快</td></tr><tr><td>效果</td><td>长序列稍占优</td><td>短中序列相当</td></tr></tbody></table><hr><h2 id="六、seq2seq-序列到序列" tabindex="-1">六、Seq2Seq（序列到序列） <a class="header-anchor" href="#六、seq2seq-序列到序列" aria-label="Permalink to &quot;六、Seq2Seq（序列到序列）&quot;">​</a></h2><p>Seq2Seq（Sequence to Sequence）是一种基于 RNN/LSTM 的<strong>编码器-解码器架构</strong>，将一个变长序列映射为另一个变长序列。</p><h3 id="整体结构" tabindex="-1">整体结构 <a class="header-anchor" href="#整体结构" aria-label="Permalink to &quot;整体结构&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入序列:  x_1  x_2  x_3  x_4</span></span>
<span class="line"><span>              ↓</span></span>
<span class="line"><span>         [编码器 Encoder]（LSTM）</span></span>
<span class="line"><span>              ↓</span></span>
<span class="line"><span>         语义向量 c（context vector）—— 压缩整个输入序列的信息</span></span>
<span class="line"><span>              ↓</span></span>
<span class="line"><span>         [解码器 Decoder]（LSTM）</span></span>
<span class="line"><span>              ↓</span></span>
<span class="line"><span>输出序列:  y_1  y_2  y_3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="编码器-encoder" tabindex="-1">编码器（Encoder） <a class="header-anchor" href="#编码器-encoder" aria-label="Permalink to &quot;编码器（Encoder）&quot;">​</a></h3><p>逐步读取输入序列 $x_1, x_2, \\ldots, x_T$，最终隐藏状态 $h_T$ 作为整个序列的语义表示（上下文向量 $c = h_T$）。</p><p>$$h_t^{enc} = \\text{LSTM}(x_t, h_{t-1}^{enc})$$</p><h3 id="解码器-decoder" tabindex="-1">解码器（Decoder） <a class="header-anchor" href="#解码器-decoder" aria-label="Permalink to &quot;解码器（Decoder）&quot;">​</a></h3><p>以 $c$ 作为初始隐藏状态，自回归地生成输出序列（每次以上一步的输出作为当前输入）：</p><p>$$h_t^{dec} = \\text{LSTM}(y_{t-1}, h_{t-1}^{dec})$$</p><p>$$P(y_t | y_{&lt;t}, c) = \\text{Softmax}(W h_t^{dec} + b)$$</p><h3 id="seq2seq-的瓶颈" tabindex="-1">Seq2Seq 的瓶颈 <a class="header-anchor" href="#seq2seq-的瓶颈" aria-label="Permalink to &quot;Seq2Seq 的瓶颈&quot;">​</a></h3><p>将整个输入序列压缩为<strong>固定长度</strong>的向量 $c$，当序列很长时信息丢失严重。<strong>注意力机制（Attention）</strong> 解决了这一问题：解码每个词时动态关注编码器不同位置的输出，而不仅依赖最后一个隐藏状态。</p><h3 id="典型应用" tabindex="-1">典型应用 <a class="header-anchor" href="#典型应用" aria-label="Permalink to &quot;典型应用&quot;">​</a></h3><table tabindex="0"><thead><tr><th>应用</th><th>输入</th><th>输出</th></tr></thead><tbody><tr><td>机器翻译</td><td>源语言句子</td><td>目标语言句子</td></tr><tr><td>文本摘要</td><td>长文本</td><td>摘要</td></tr><tr><td>语音识别</td><td>音频序列</td><td>文字序列</td></tr><tr><td>对话系统</td><td>问题</td><td>回答</td></tr></tbody></table><hr><h2 id="七、知识小结" tabindex="-1">七、知识小结 <a class="header-anchor" href="#七、知识小结" aria-label="Permalink to &quot;七、知识小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识点</th><th>核心内容</th><th>易混淆点</th><th>难度</th></tr></thead><tbody><tr><td>RNN 结构</td><td>$h_t = f(W_h h_{t-1} + W_x x_t + b)$，参数跨时间步共享</td><td>与全连接区别：有&quot;记忆&quot;$h_t$</td><td>⭐⭐</td></tr><tr><td>BPTT</td><td>反向传播在时间轴上展开，梯度沿时间累加</td><td>序列越长，乘积链越长</td><td>⭐⭐⭐</td></tr><tr><td>梯度消失</td><td>$\\lvert W_h\\rvert&lt;1$ 时多步连乘趋零，远处信息丢失</td><td>根本原因：覆盖式更新</td><td>⭐⭐⭐</td></tr><tr><td>LSTM</td><td>细胞状态 $c_t$ + 遗忘/输入/输出三门，加法更新保留梯度</td><td>$c_t$ vs $h_t$ 的区别</td><td>⭐⭐⭐</td></tr><tr><td>GRU</td><td>简化 LSTM，重置门 + 更新门，参数更少</td><td>GRU 无独立细胞状态</td><td>⭐⭐⭐</td></tr><tr><td>Seq2Seq</td><td>编码器压缩输入 → 上下文向量 $c$ → 解码器生成输出</td><td>瓶颈问题：$c$ 长度固定</td><td>⭐⭐⭐</td></tr><tr><td>Attention</td><td>解码时动态关注编码器各位置（非本文重点，详见 Transformer）</td><td>Attention 解决 Seq2Seq 瓶颈</td><td>⭐⭐⭐⭐</td></tr></tbody></table>`,23)]))}const u=r(o,[["render",l]]);export{b as __pageData,u as default};
